import os
import re
from flask import Flask, send_from_directory, abort, safe_join
from werkzeug.utils import secure_filename
from pathlib import Path

app = Flask(__name__)

UPLOAD_FOLDER = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'uploads')
app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER

os.makedirs(UPLOAD_FOLDER, exist_ok=True)

LEGACY_FILENAME_PATTERNS = {
    r'^file_(\d+)_(.+)$': r'file-\1-\2',
    r'^document\.(\d+)\.(.+)$': r'document_\1.\2',
    r'^img_(\d{8})_(.+)$': r'img-\1-\2',
    r'^upload_([a-zA-Z0-9]+)_(.+)$': r'upload-\1-\2',
}

def normalize_legacy_filename(filename):
    if not filename:
        return None
    
    filename = secure_filename(filename)
    
    for pattern, replacement in LEGACY_FILENAME_PATTERNS.items():
        match = re.match(pattern, filename)
        if match:
            try:
                normalized = re.sub(pattern, replacement, filename)
                return normalized
            except:
                continue
    
    return filename

def find_file_with_legacy_support(filename):
    if not filename:
        return None
    
    filename = secure_filename(filename)
    
    direct_path = safe_join(UPLOAD_FOLDER, filename)
    if direct_path and os.path.isfile(direct_path):
        return filename
    
    normalized = normalize_legacy_filename(filename)
    if normalized and normalized != filename:
        normalized_path = safe_join(UPLOAD_FOLDER, normalized)
        if normalized_path and os.path.isfile(normalized_path):
            return normalized
    
    try:
        files = os.listdir(UPLOAD_FOLDER)
        for existing_file in files:
            if secure_filename(existing_file) == filename:
                return existing_file
            
            normalized_existing = normalize_legacy_filename(existing_file)
            if normalized_existing == filename:
                return existing_file
    except (OSError, PermissionError):
        pass
    
    return None

@app.route('/uploads/<path:filename>')
def serve_upload(filename):
    if not filename:
        abort(400)
    
    if '..' in filename or filename.startswith('/') or filename.startswith('\\'):
        abort(400)
    
    actual_filename = find_file_with_legacy_support(filename)
    
    if not actual_filename:
        abort(404)
    
    try:
        file_path = safe_join(UPLOAD_FOLDER, actual_filename)
        if not file_path:
            abort(400)
        
        real_path = os.path.realpath(file_path)
        real_upload_folder = os.path.realpath(UPLOAD_FOLDER)
        
        if not real_path.startswith(real_upload_folder):
            abort(403)
        
        if not os.path.isfile(real_path):
            abort(404)
        
        return send_from_directory(UPLOAD_FOLDER, actual_filename)
    except (OSError, PermissionError):
        abort(403)

@app.route('/legacy-uploads/<path:filename>')
def serve_legacy_upload(filename):
    if not filename:
        abort(400)
    
    if '..' in filename or filename.startswith('/') or filename.startswith('\\'):
        abort(400)
    
    filename = secure_filename(filename)
    normalized = normalize_legacy_filename(filename)
    
    if normalized:
        actual_filename = find_file_with_legacy_support(normalized)
        if actual_filename:
            try:
                file_path = safe_join(UPLOAD_FOLDER, actual_filename)
                if not file_path:
                    abort(400)
                
                real_path = os.path.realpath(file_path)
                real_upload_folder = os.path.realpath(UPLOAD_FOLDER)
                
                if not real_path.startswith(real_upload_folder):
                    abort(403)
                
                if not os.path.isfile(real_path):
                    abort(404)
                
                return send_from_directory(UPLOAD_FOLDER, actual_filename)
            except (OSError, PermissionError):
                abort(403)
    
    abort(404)

if __name__ == '__main__':
    app.run(debug=False, host='127.0.0.1', port=5000)